package vasyurin.work.services;import vasyurin.work.entities.MaxId;import vasyurin.work.entities.Transaction;import vasyurin.work.entities.Wallet;import vasyurin.work.enums.TransactionTypes;import vasyurin.work.exeption.NoMoneyException;import vasyurin.work.kafka.KafkaBatchSchedulerService;import vasyurin.work.services.interfaces.MaxIdService;import vasyurin.work.services.interfaces.TransactionService;import java.util.List;public class TransactionServiceImpl implements TransactionService {    private static final MaxIdService maxIdService = new MaxIdServiceImpl();    private KafkaBatchSchedulerService kafkaBatchSchedulerServiceService;    public TransactionServiceImpl() {}    public TransactionServiceImpl(KafkaBatchSchedulerService kafkaBatchSchedulerService) {        this.kafkaBatchSchedulerServiceService = kafkaBatchSchedulerService;    }    @Override    public void createTransaction(Wallet senderWallet, Wallet receiverWallet, int sumTransaction) {        MaxId maxId = maxIdService.getMaxId(senderWallet, receiverWallet);        Transaction income = new Transaction(maxId.maxRID() + 1, receiverWallet.getId(), sumTransaction, TransactionTypes.INCOME);        Transaction expense = new Transaction(maxId.maxSID() + 1, senderWallet.getId(), sumTransaction, TransactionTypes.EXPENSE);        if (senderWallet.getBalance() >= sumTransaction) {            receiverWallet.addTransaction(income);            senderWallet.addTransaction(expense);        } else {            if (kafkaBatchSchedulerServiceService != null) {                kafkaBatchSchedulerServiceService.addMessageToBatch("transactions", "У кошелька " + senderWallet.getId() + " недостаточно средств");            }            throw new NoMoneyException("Недостаточно средств");        }        if (kafkaBatchSchedulerServiceService != null){            kafkaBatchSchedulerServiceService.addMessageToBatch("transactions", "Transaction income completed, id: " + income.getId() + " wallet id: " + receiverWallet.getId());            kafkaBatchSchedulerServiceService.addMessageToBatch("transactions", "Transaction expense completed, id: " + expense.getId() + " wallet id: " + senderWallet.getId());        }        System.out.println("Транзакция успешно проведена");    }    @Override    public Float getSumOfAllTransaction(List<Transaction> transactions) {        float summ = 0;        for (Transaction transaction : transactions) {            if (transaction.getType().equals(TransactionTypes.INCOME)) {                summ += transaction.getAmount();            } else if (transaction.getType().equals(TransactionTypes.EXPENSE)) {                summ -= transaction.getAmount();            }        }        return summ;    }}